<?php require_once '../config/db.php'; require_once '../includes/auth.php'; require_admin(); $page_title='Equipment'; if(isset($_GET['delete'])){mysqli_query($conn,'DELETE FROM EQUIPMENT WHERE equipment_id='.intval($_GET['delete'])); header('Location: equipment.php'); exit();} if($_SERVER['REQUEST_METHOD']==='POST'){ $stmt=mysqli_prepare($conn,'INSERT INTO EQUIPMENT(equipment_name,category,quantity_available,condition_status,last_maintenance_date) VALUES(?,?,?,?,?)'); mysqli_stmt_bind_param($stmt,'ssiss',$_POST['equipment_name'],$_POST['category'],$_POST['quantity_available'],$_POST['condition_status'],$_POST['last_maintenance_date']); mysqli_stmt_execute($stmt); header('Location: equipment.php'); exit(); } $result=mysqli_query($conn,'SELECT * FROM EQUIPMENT ORDER BY equipment_id DESC'); require_once '../includes/header.php'; require_once '../includes/sidebar.php'; ?>
